
import {  ACTION_PRODUCTS_FETCHED, ACTION_PRODUCTS_FETCH_ERROR, ACTION_ADD_SELECTED_PRODUCT, ACTION_REMOVE_SELECTED_PRODUCT, GlobalAction, ProductState } from "../types";

const INTIAL_PRODUCT_STATE: ProductState = {
    productCategories: [],
    selectedProducts: [],
    hasError: false
  }
  export function productsReducer(state: ProductState = INTIAL_PRODUCT_STATE, action: GlobalAction): ProductState {
  
    switch (action.type) {
      case ACTION_PRODUCTS_FETCHED:
        return {
          ...state,
          productCategories: action.payload,
          selectedProducts:[]
        };
  
      case ACTION_ADD_SELECTED_PRODUCT:
        {
          for (let category of state.productCategories) {
            let selectProduct = category.products.find(p => p.id == action.payload)
  
            if (selectProduct) {
              return { ...state, selectedProducts: [selectProduct, ...state.selectedProducts] }
            }
          }
        }
  
      case ACTION_REMOVE_SELECTED_PRODUCT:
        return {
          ...state, selectedProducts: state.selectedProducts.filter(p => p.id != action.payload)
        }
      case ACTION_PRODUCTS_FETCH_ERROR:
        return {
          ...state, hasError: true
        }
  
      default:
        return state;
    }
  
  }
  
  
  