import { Checkbox } from '@material-ui/core'
import React from 'react'
import { BillingFreq, Product } from '../../../redux/types'

import styles from './ProductViewer.module.css'

interface ProductViewerProps {
    product: Product,
    onChecked:(productId:Number,isChecked:Boolean)=>void
}

export default function ProductViewer(props: ProductViewerProps) {
    return <div className={styles["product-viewer-container"]}>
        <div className={styles["product-view-checkbox"]}> <Checkbox color="primary" onChange={(_,isChecked)=>props.onChecked(props.product.id,isChecked)}/></div>

        <div className={styles["product-viewer-details"]}>
            <div className={styles["product-viewer-name"]}>
            {props.product.name}
        </div>

        <div className={styles["product-viewer-description"]}>
            {props.product.description}
        </div>


        <div className={styles["product-viewer-price"]}>
           <h2> {`${props.product.price[0].amount} € / ${BillingFreq[props.product.price[0].billingFrequency]}`}</h2>
            <div className={styles["product-viewer-price-note"]}>{props.product.price.length>1?`From ${props.product.price[1].periodStart} ${props.product.price[1].amount} € / ${BillingFreq[props.product.price[1].billingFrequency]}`:null}</div>
        </div>
        </div>
    </div>
}