import React, { Fragment, ReactElement, useEffect } from "react";
import { Dispatch } from "redux";
import styles from './ProductList.module.css';
import { connect } from "react-redux";
import { GlobalState, ProductCategory, ProductState } from "../../../redux/types";
import { getProducts } from "../../../redux/selectors";
import { fetchProducts, addSelectedProduct, removeSelectedProduct } from "../../../redux/actions";
import ProductViewer from "../../common/ProductViewer/ProductViewer";
import Header from '../../common/header/header'
import { Button } from "@material-ui/core";
import { Link, Redirect } from "react-router-dom";
import Loading from '../../common/loading/loading'
import { stringify } from "querystring";

interface ProductListStateProps {
    products: Array<ProductCategory>;
}

interface ProductListDispatchProps {
    addSelectedProduct: (id: Number) => void;
    removeSelectedProduct: (id: Number) => void;
    fetchProducts: () => void
}

interface ProductsListProps extends ProductListStateProps {
    onChange: (productId: Number, isChecked: Boolean) => void;
    fetchProducts: () => void
}

function mapStateToProps(state: GlobalState): ProductListStateProps {
    return {
        products: getProducts(state)
    }
}

function mapDispatchToProps(dispatch: Dispatch) {
    return {
        fetchProducts: () => dispatch(fetchProducts()),
        addSelectedProduct: (id: Number) => dispatch(addSelectedProduct(id)),
        removeSelectedProduct: (id: Number) => dispatch(removeSelectedProduct(id))
    }
}

function mergeProps(stateProps: ProductListStateProps, dispatchProps: ProductListDispatchProps): ProductsListProps {
    return {
        ...stateProps,
        onChange: (id: Number, isChecked: Boolean): void => {
            isChecked ? dispatchProps.addSelectedProduct(id) : dispatchProps.removeSelectedProduct(id)
        },
        fetchProducts: dispatchProps.fetchProducts
    }
}

function ProductList(props: ProductsListProps): ReactElement {
    useEffect(() => {
        props.fetchProducts()
    }, [])


    return (
        <Fragment>
        <Header headerText={"Products"} navigationPath="/"/>
                    
        <div className={styles["category-container"]}>
            {props.products && props.products.length ? props.products.map(p => <div key={`${p.name}`} className={styles["product-category"]}><div className={styles["category-title"]}> {p.name}</div>
                <div className={styles["products-container"]}>
                    {
                        p.products.map(product=><span key={parseInt(product.id.toString())} className={styles["product-viewer-container"]}><ProductViewer onChecked={props.onChange} product={product}/></span>)
                    }
                </div>
            </div>) : <Loading/>}

            <div className="navigationLink"> <Link className={styles["basket-btn"]} to='/basket'> Basket</Link></div>
        </div>
        </Fragment>
    );
}

export default connect(mapStateToProps, mapDispatchToProps, mergeProps)(ProductList);
