import React from 'react'
import styles from './header.module.css'
import { HighlightOff, ArrowRight } from '@material-ui/icons';
import {Link} from 'react-router-dom'
interface headerProps {
    headerText: String,
    navigationPath?: String
}

export default (props: headerProps) => {
    return <div className={styles["header-container"]}><span><ArrowRight color="primary" fontSize="large" /></span><span className={styles["header-text"]}>{props.headerText}</span><Link className={styles.closeLink} to={`${props.navigationPath}`}><HighlightOff color="primary" fontSize="large" /></Link> </div>
}