export const ACTION_SET_DARK_MODE = "ACTION_SET_DARK_MODE";
export const ACTION_PRODUCTS_FETCHED = "ACTION_PRODUCTS_FETCHED";
export const ACTION_PRODUCTS_FETCH_ERROR = "ACTION_PRODUCTS_FETCH_ERROR";
export const ACTION_ADD_SELECTED_PRODUCT = "ACTION_ADD_SELECTED_PRODUCT";
export const ACTION_REMOVE_SELECTED_PRODUCT = "ACTION_REMOVE_SELECTED_PRODUCT";

export interface ActionSetDarkMode {
  type: typeof ACTION_SET_DARK_MODE;
  payload: boolean;
}

export interface ActionAddSelectedProduct {
  type: typeof ACTION_ADD_SELECTED_PRODUCT,
  payload: Number
}


export interface ActionRemoveSelectedProduct {
  type: typeof ACTION_REMOVE_SELECTED_PRODUCT,
  payload: Number
}

export interface ActionProductsFetchError {
  type: typeof ACTION_PRODUCTS_FETCH_ERROR
}

export interface ActionProductsFetched {
  type: typeof ACTION_PRODUCTS_FETCHED,
  payload: Array<ProductCategory>
}

export type UiAction = ActionSetDarkMode;

export type ProductActions = ActionProductsFetched | ActionAddSelectedProduct | ActionRemoveSelectedProduct | ActionProductsFetchError

export type GlobalAction = UiAction | ProductActions;

export type UiState = Readonly<{
  darkMode: boolean;
}>;

export type ProductState=Readonly<{
  productCategories: Array<ProductCategory>,
  selectedProducts: Array<Product>,
  hasError: Boolean
}>

export type GlobalState = Readonly<{
  uiState: UiState;
  productsState:ProductState
}>;



//DTOS
export interface ProductCategory {
  name: String
  products: Array<Product>
}

export interface Product {
  id:Number,
  name: String,
  description: String,
  price: Array<Price>,
  
}

export interface Price {
  amount: Number,
  periodStart?: Number
  billingFrequency: typeof BillingFreq
}

export const BillingFreq:any= {
  ONCE:"One time", MONTHLY:"Month"
}