import { Selector } from "react-redux";
import { GlobalState, Product, ProductCategory, ProductState } from "./types";

export const getDarkMode: Selector<GlobalState, boolean> = state => state.uiState.darkMode;
export const getProducts: Selector<GlobalState, Array<ProductCategory>> = state => state.productsState.productCategories
export const getSelectedProducts: Selector<GlobalState, Array<Product>> = state => state.productsState.selectedProducts