import React from 'react';
import './App.css';
import DarkMode from "./components/HOC/darkmode/DarkMode";
import { GlobalState } from "./redux/types";
import { getDarkMode } from "./redux/selectors";
import { connect } from "react-redux";
import { BrowserRouter as Router, Switch, Link, Route } from 'react-router-dom'
import ProductsList from './components/HOC/ProductsList/ProductsList'
import Basket from './components/HOC/Basket/Basket'
import { Button } from '@material-ui/core';
interface AppProps {
  darkMode: boolean;
}


function mapStateToProps(state: GlobalState): AppProps {
  return {
    darkMode: getDarkMode(state)
  };
}


const StartPage = () => <div className="startContainer"><div className="navigationLink"><Link to="/products"> Start</Link></div></div>


function App(props: AppProps) {
  return (
    <Router>
      <div className={`app ${props.darkMode ? 'app--dark-mode' : ''}`}>
        <DarkMode />

        <Switch>
          <Route path="/products" component={ProductsList} exact />
          <Route path="/basket" component={Basket} exact />
          <Route path="/" component={StartPage} />
        </Switch>
      </div>
    </Router>
  );
}

export default connect(mapStateToProps)(App);
