import { ACTION_SET_DARK_MODE, ActionSetDarkMode, ACTION_PRODUCTS_FETCHED, ACTION_PRODUCTS_FETCH_ERROR, ProductCategory, ActionAddSelectedProduct, ACTION_ADD_SELECTED_PRODUCT, ACTION_REMOVE_SELECTED_PRODUCT, ActionRemoveSelectedProduct } from "./types";

import axios from 'axios'
import { Dispatch } from "redux";

export function setDarkMode(darkMode: boolean): ActionSetDarkMode {
  return {
    type: ACTION_SET_DARK_MODE,
    payload: darkMode
  };
}

export function addSelectedProduct(id: Number): ActionAddSelectedProduct {
  return {
    type: ACTION_ADD_SELECTED_PRODUCT,
    payload: id
  }
}



export function removeSelectedProduct(id: Number): ActionRemoveSelectedProduct {
  return {
    type: ACTION_REMOVE_SELECTED_PRODUCT,
    payload: id
  }
}

export function fetchProducts(): any {
  
  return async (dispatch: Dispatch) => {
    try {
      let products = (await axios.get(`${process.env["REACT_APP_BASE_URL"]}/data.json`)).data
      dispatch({
        type: ACTION_PRODUCTS_FETCHED,
        payload: products.productCategories
      })
    }
    catch {
      dispatch({
        type: ACTION_PRODUCTS_FETCH_ERROR,
      })
    }
  }
}