import React, { Fragment, ReactElement, useEffect } from "react";
import styles from './Basket.module.css';
import { connect } from "react-redux";
import { BillingFreq, GlobalState, Product, ProductCategory, ProductState } from "../../../redux/types";
import { getSelectedProducts } from "../../../redux/selectors";
import Header from '../../common/header/header'

import { Link } from "react-router-dom";

interface BasketStateProps {
    products: Array<Product>;
}

function mapStateToProps(state: GlobalState): BasketStateProps {
    return {
        products: getSelectedProducts(state)
    }
}

function ProductList(props: BasketStateProps): ReactElement {

    return (
        <Fragment>
        <Header headerText={"Baskets"} navigationPath="/products"/>
                    <h3 className={styles["overview"]}>Overview</h3>
            {props.products && props.products.length ?
                <div className={styles["products-container"]}>
                    {
                        props.products.map(product=><div className={styles["products-details"]}><div className={styles["products-name"]}>{product.name}</div><div className={styles["products-price"]}>{`${product.price[0].amount} €/${BillingFreq[product.price[0].billingFrequency]}`}</div></div>)
                    }
                </div> :<div className={styles["no-records"]}>No Selected Products</div> }

            <div className="navigationLink"> <Link className={styles["orderBtn"]} to='/'> Order</Link></div>
          </Fragment>
    );
}

export default connect(mapStateToProps)(ProductList);
